// ---------------------------------------------------------------------------
// T2.4: Recomputed focus score > 0 when productive ratio is high
// ---------------------------------------------------------------------------

#[test]
fn report_RecomputedFocus_PositiveWhenProductiveRatioHigh() {
    let conn = init_db(":memory:").unwrap();

    let today = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();

    for i in 0..10 {
        let record = ActivityRecord {
            timestamp: today.clone(),
            computer_name: "test-host".to_string(),
            primary_domain: "WORKGROUP".to_string(),
            local_ip: "127.0.0.1".to_string(),
            public_ip: "0.0.0.0".to_string(),
            logon_domain: "test-host".to_string(),
            user_name: "tester".to_string(),
            session_id: "focus-session".to_string(),
            duration_seconds: 300,
            window_title: format!("editor window {i}"),
            executable_name: "Code".to_string(),
            app_description: "Visual Studio Code".to_string(),
            url: String::new(),
            productivity_status: "Productive Active".to_string(),
            is_video: false,
            is_context_switch: i > 0,
        };
        insert_activity(&conn, &record).unwrap();
    }

    let metrics = DailyMetrics {
        date: chrono::Utc::now().format("%Y-%m-%d").to_string(),
        focus_score: Some(0),
        deep_work_minutes: Some(40),
        deep_work_streak_count: Some(2),
        longest_streak_minutes: Some(25),
        context_switches: Some(9),
        switches_per_hour: Some(1.8),
        productive_minutes: Some(50),
        unproductive_minutes: Some(0),
        passive_minutes: Some(0),
        uncategorized_minutes: Some(0),
        total_tracked_minutes: Some(50),
    };
    upsert_daily_metrics(&conn, &metrics).unwrap();

    let rule_set = RuleSet {
        rules: vec![ProductivityRule {
            match_executable: Some("Code".to_string()),
            match_title_contains: None,
            match_url_contains: None,
            status: "Productive Active".to_string(),
        }],
        default_status: "Uncategorized".to_string(),
    };

    let m = activtrak::insights::reclassify_today(&conn, &rule_set).unwrap();
    assert!(
        m.productive_secs > 0,
        "productive_secs should be > 0 after reclassification, got {}",
        m.productive_secs
    );
    assert!(
        m.total_secs > 0,
        "total_secs should be > 0, got {}",
        m.total_secs
    );

    let weights = FocusScoreWeights {
        deep_work: 0.40,
        switch_rate: 0.30,
        productive: 0.30,
    };
    let calc = FocusScoreCalculator::new(weights);

    #[allow(clippy::cast_precision_loss)]
    let input = FocusScoreInput {
        deep_work_minutes: metrics.deep_work_minutes.unwrap_or(0) as f64,
        total_tracked_minutes: (m.total_secs as f64) / 60.0,
        switches_per_hour: metrics.switches_per_hour.unwrap_or(0.0),
        max_switches_per_hour: 30.0,
        productive_minutes: (m.productive_secs as f64) / 60.0,
    };
    let focus = calc.compute(&input);

    assert!(
        focus > 0,
        "focus score should be > 0 when productive ratio is high, got {focus}"
    );
}

